sql.where:


    AND id = #{id, jdbcType=BIGINT}


    AND id IN

        #{item, jdbcType=BIGINT}





        AND create_time >= #{createTime[0], jdbcType=TIMESTAMP}


        AND create_time <= #{createTime[1], jdbcType=TIMESTAMP}


        AND create_time BETWEEN #{createTime[0], jdbcType=TIMESTAMP}
        AND #{createTime[1], jdbcType=TIMESTAMP}




        AND update_time >= #{updateTime[0], jdbcType=TIMESTAMP}


        AND update_time <= #{updateTime[1], jdbcType=TIMESTAMP}


        AND update_time BETWEEN #{updateTime[0], jdbcType=TIMESTAMP}
        AND #{updateTime[1], jdbcType=TIMESTAMP}




    AND parent_id = #{parentId, jdbcType=BIGINT}


    AND application_id = #{applicationId, jdbcType=BIGINT}


    AND menu_name = #{menuName, jdbcType=VARCHAR}


    AND menu_code = #{menuCode, jdbcType=VARCHAR}


    AND link_path = #{linkPath, jdbcType=VARCHAR}


    AND icon = #{icon, jdbcType=VARCHAR}


    AND menu_sort_order = #{menuSortOrder, jdbcType=INTEGER}


AND (delete_flag = 0 OR delete_flag IS NULL)

mapper.select:
SELECT DISTINCT rm.id, rm.parent_id, rm.application_id, rm.menu_name, rm.menu_code, rm.link_path, rm.icon, rm.menu_sort_order FROM user_role_relation urr JOIN role_control_unit_relation rcur ON urr.`role_id` = rcur.`role_id` AND rcur.`delete_flag` = 0 AND rcur.`status` = 'ACTIVATED' JOIN control_unit_resource_relation curr ON rcur.`control_unit_id` = curr.`control_unit_id` AND curr.`delete_flag` = 0 AND curr.`resource_type` = 'MENU' JOIN resource_menu rm ON curr.`resource_id` = rm.`id` AND rm.`delete_flag` = 0 AND rm.`application_id` in
#{id}
WHERE urr.`delete_flag` = 0 AND urr.`user_id` = #{userId}
